use crate::api::*;
use std::sync::RwLock;
use std::collections::HashMap;

pub struct VectorDB {
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut store = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            store.insert(id, vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        let k = top_k as usize;

        // Pre-allocate capacity for top_k results
        let mut results: Vec<(u64, f64)> = Vec::with_capacity(k);

        // Collect distances for all vectors
        for (id, stored_vector) in vectors.iter() {
            let dist = crate::distance::l2_distance(vector, stored_vector);
            results.push((*id, dist));
        }

        // Use partial sort - much faster than full sort
        if results.len() > k {
            // Use select_nth_unstable to partition around the kth element
            // This gives us the k smallest elements but unsorted
            let mid = results.len() - k;
            results.select_nth_unstable(mid);

            // Now results[k:] contains the k smallest elements
            // Extract and sort them
            let tail = results.split_off(results.len() - k);
            tail.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

            tail.into_iter()
                .map(|(id, distance)| SearchResult { id, distance })
                .collect()
        } else {
            results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
            results
                .into_iter()
                .map(|(id, distance)| SearchResult { id, distance })
                .collect()
        }
    }
}

use crate::api::*;
use std::sync::RwLock;
use std::collections::HashMap;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub struct VectorDB {
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut store = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            store.insert(id, vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        let k = top_k as usize;

        // Use a BinaryHeap (max-heap) to keep track of top-k smallest distances
        // We store Reverse<(f64, u64)> so the smallest distances come out first
        let mut heap: BinaryHeap<Reverse<(f64, u64)>> = BinaryHeap::with_capacity(k);

        for (id, stored_vector) in vectors.iter() {
            let dist = crate::distance::l2_distance(vector, stored_vector);

            if heap.len() < k {
                heap.push(Reverse((*id, dist)));
            } else if let Some(Reverse((_, largest_dist))) = heap.peek() {
                if dist < *largest_dist {
                    heap.pop();
                    heap.push(Reverse((*id, dist)));
                }
            }
        }

        // Extract all elements from heap and sort
        let mut results: Vec<SearchResult> = heap
            .into_inner()
            .into_iter()
            .map(|Reverse((id, distance))| SearchResult { id, distance })
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}

