pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        }
    }

    // Fallback to scalar
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let diff = *x - *y;
            (diff * diff) as f64
        })
        .sum()
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();

    let mut i = 0;
    let chunks = a.len() / 16;

    for _ in 0..chunks {
        let a_vec = _mm512_loadu_ps(a.as_ptr().add(i));
        let b_vec = _mm512_loadu_ps(b.as_ptr().add(i));

        let diff = _mm512_sub_ps(a_vec, b_vec);
        let sq = _mm512_mul_ps(diff, diff);
        sum = _mm512_add_ps(sum, sq);

        i += 16;
    }

    // Horizontal sum of the 512-bit register
    let mut result: f32 = 0.0;

    // Sum lower and upper 256 bits
    let sum256_lo = _mm512_castps512_ps256(sum);
    let sum256_hi = _mm512_extractf32x8_ps(sum, 1);
    let sum256 = _mm256_add_ps(sum256_lo, sum256_hi);

    // Sum 128-bit halves
    let sum128_lo = _mm256_castps256_ps128(sum256);
    let sum128_hi = _mm256_extractf128_ps(sum256, 1);
    let sum128 = _mm_add_ps(sum128_lo, sum128_hi);

    // Sum 64-bit halves
    let sum64_lo = _mm_castps_ps128(sum128);
    let sum64_hi = _mm_movehl_ps(sum128, sum128);
    let sum64 = _mm_add_ss(sum64_lo, sum64_hi);

    // Final sum
    result = _mm_cvtss_f32(sum64);

    // Handle remainder
    let remainder = a.len() % 16;
    if remainder > 0 {
        for j in 0..remainder {
            let diff = a[i + j] - b[i + j];
            result += diff * diff;
        }
    }

    result as f64
}

